import { signal, computed } from '@angular/core';

type Theme = 'light' | 'dark' | 'system';
type Locale = 'en' | 'fr' | 'de' | 'es';

interface AppSettings {
  theme: Theme;
  locale: Locale;
  fontSize: 12 | 14 | 16 | 18 | 20;
}

@Injectable({ providedIn: 'root' })
class SettingsService {
  private settings = signal<AppSettings>({
    theme: 'system',
    locale: 'en',
    fontSize: 16,
  });

  readonly theme  = computed(() => this.settings().theme);
  readonly locale = computed(() => this.settings().locale);

  setTheme(theme: Theme): void {
    this.settings.update(s => ({ ...s, theme }));
  }

  setLocale(locale: Locale): void {
    this.settings.update(s => ({ ...s, locale }));
  }
}

type Status = 'idle' | 'loading' | 'success' | 'error';

function getLabel(status: Status): string {
  // TypeScript narrows status inside each branch
  if (status === 'loading') return 'Please wait…';
  if (status === 'success') return 'Done!';
  if (status === 'error')   return 'Something went wrong.';
  // status: 'idle' — only remaining member
  return 'Ready';
}

// switch narrows too
function getIcon(status: Status): string {
  switch (status) {
    case 'idle':    return '⏸';
    case 'loading': return '⏳';
    case 'success': return '✅';
    case 'error':   return '❌';
  }
}

