// Parse a route pattern into parameter names
type RouteParams<T extends string> =
  T extends `${string}:${infer Param}/${infer Rest}`
    ? Param | RouteParams<Rest>
    : T extends `${string}:${infer Param}`
    ? Param
    : never;

type Params = RouteParams<'/users/:userId/posts/:postId'>;
// 'userId' | 'postId'

// Build a type-safe router
function navigate<T extends string>(
  pattern: T,
  params: { [K in RouteParams<T>]: string }
): string {
  let url: string = pattern;
  for (const [key, value] of Object.entries(params)) {
    url = url.replace(`:${key}`, value as string);
  }
  return url;
}

const url = navigate('/users/:userId/posts/:postId', {
